    const nd = &re.nodes[state];
    switch (nd.kind) {
        .split => {
            try _re_eclosure_s(re, cur, vis, alloc, nd.out1, saves, pos, input);
            try _re_eclosure_s(re, cur, vis, alloc, nd.out2, saves, pos, input);
